package com.samudhra.certificates.config;
import org.springframework.beans.factory.annotation.Value; import org.springframework.context.annotation.Configuration; import org.springframework.web.servlet.config.annotation.*;
@Configuration public class WebConfig implements WebMvcConfigurer { @Value("${app.upload-dir}") String uploads; @Override public void addCorsMappings(CorsRegistry r){r.addMapping("/api/**").allowedOriginPatterns("*").allowedMethods("GET","POST","PUT","DELETE","OPTIONS").allowedHeaders("*");} @Override public void addResourceHandlers(ResourceHandlerRegistry r){String projectDir = new java.io.File("./").getAbsoluteFile().toURI().toString(); String uploadDir = new java.io.File(uploads).getAbsoluteFile().toURI().toString(); r.addResourceHandler("/uploads/**").addResourceLocations(uploadDir); r.addResourceHandler("/**").addResourceLocations(projectDir);} @Override public void addViewControllers(ViewControllerRegistry registry){registry.addViewController("/").setViewName("forward:/index.html");} }
